const history = $input.all().map(i => i.json);
const destination = history[0]?.destination || "Tokyo";
const userId = $('Webhook').first().json.body.userId;
const categories = history.map(h => h.category).filter(Boolean);
const queries = history.map(h => h.query).filter(Boolean);
const categoryCounts = {};
categories.forEach(c => { categoryCounts[c] = (categoryCounts[c] || 0) + 1; });
const topCategories = Object.entries(categoryCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(e => e[0]);
const recentQueries = queries.slice(0, 5).join(', ');
return [{
  json: {
    userId,
    destination,
    topCategories,
    recentQueries,
    historyCount: history.length
  }
}];

