const response = $json.responses[0].message.content;
const cleaned = response.replace(/```json/g, '').replace(/```/g, '').trim();

let queries;
try {
  queries = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { queries = JSON.parse(match[0]); } 
    catch { queries = null; }
  }
}

if (!queries) {
  queries = {
    trending: 'trending tourist spots',
    seasonal: 'seasonal attractions',
    hidden_gems: 'hidden gems underrated',
    local: 'local experiences authentic'
  };
}

const destination = $('Webhook').first().json.body.destination;
const userId = $('Webhook').first().json.body.userId;

return Object.entries(queries).map(([category, query]) => ({
  json: { category, query, destination, userId }
}));

const response = $json.responses[0].message.content;
const cleaned = response.replace(/```json/g, '').replace(/```/g, '').trim();
let places = [];
try { places = JSON.parse(cleaned); } catch(e) { places = []; }

const destination = $('Webhook').first().json.body.destination;
const userId = $('Webhook').first().json.body.userId;

// Extract category from the query string prefix [category]
const queryStr = $json.query || '';
const categoryMatch = queryStr.match(/^\[([^\]]+)\]/);
const category = categoryMatch ? categoryMatch[1] : 'general';

return places.slice(0,3).map(place => ({ 
  json: { placeName: place, destination, category, userId } 
}));

const destination = $('analyse history').first().json.destination;
const userId = $('Webhook').first().json.body.userId;

return $input.all().map(item => {
  if (item.json.error) return null;
  const response = item.json.responses?.[0]?.message?.content;
  if (!response) return null;
  const cleaned = response.replace(/```json/g, '').replace(/```/g, '').trim();
  let parsed;
  try { parsed = JSON.parse(cleaned); }
  catch(e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) { try { parsed = JSON.parse(match[0]); } catch { return null; } }
    else return null;
  }
  if (!parsed.placeName || parsed.placeName === 'Unknown') return null;
  if (!parsed.verdict) return null;
  return { json: { ...parsed, destination, userId } };
}).filter(i => i !== null);

const GOOGLE_PLACES_KEY = "REMOVED_MAPS_KEY";

const rekaItems = $('clean reka output').all();

return $input.all().map((item, i) => {
  const data = rekaItems[i]?.json ?? {};
  const photoData = item.json;

  let photoUrl = null;
  const photoName = photoData?.places?.[0]?.photos?.[0]?.name;
  if (photoName) {
    photoUrl = `https://places.googleapis.com/v1/${photoName}/media?maxHeightPx=800&key=${GOOGLE_PLACES_KEY}`;
  }

  const userId = $('Webhook').first().json.body.userId;
  const destination = data.destination;

  return {
    json: {
      userId,
      destination,
      title: `✨ ${data.placeName ?? "Recommendation"}`,
      verdict: data.verdict,
      confidence: data.confidence,
      rating: data.rating,
      reviewCount: data.reviewCount,
      summary: data.reason,
      url: data.url || null,
      photoUrl: photoUrl
    }
  };
});

